namespace sv_89570eeee9ef42baa859fc8654482ee2.Models;

public class WizardData
{
    // Step 1: Personal Info
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2: Experience
    public List<JobExperience> Experience { get; set; } = new();

    // Step 3: References
    public List<Reference> References { get; set; } = new();

    // Progress tracking
    public HashSet<int> CompletedSteps { get; set; } = new();
    public int CurrentStep { get; set; } = 1;

    public DateTime LastAccessed { get; set; } = DateTime.UtcNow;
}

public class JobExperience
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class Reference
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_89570eeee9ef42baa859fc8654482ee2.Models;

namespace sv_89570eeee9ef42baa859fc8654482ee2.Services;

/// <summary>
/// Singleton service storing wizard data keyed by session ID.
/// Each browser session gets an isolated WizardData instance.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionKey)
    {
        return _store.GetOrAdd(sessionKey, _ => new WizardData());
    }

    /// <summary>
    /// Remove sessions older than the specified duration to prevent memory leaks.
    /// Call periodically from a background service.
    /// </summary>
    public void CleanupExpired(TimeSpan maxAge)
    {
        var cutoff = DateTime.UtcNow - maxAge;
        foreach (var kvp in _store)
        {
            if (kvp.Value.LastAccessed < cutoff)
            {
                _store.TryRemove(kvp.Key, out _);
            }
        }
    }
}

namespace sv_89570eeee9ef42baa859fc8654482ee2.Services;

/// <summary>
/// Background service that periodically removes expired wizard sessions.
/// </summary>
public class WizardCleanupService : BackgroundService
{
    private readonly WizardStateService _wizardState;
    private static readonly TimeSpan CleanupInterval = TimeSpan.FromMinutes(30);
    private static readonly TimeSpan MaxSessionAge = TimeSpan.FromHours(24);

    public WizardCleanupService(WizardStateService wizardState)
    {
        _wizardState = wizardState;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(CleanupInterval, stoppingToken);
            _wizardState.CleanupExpired(MaxSessionAge);
        }
    }
}

