using Microsoft.AspNetCore.Components;
using sv_89570eeee9ef42baa859fc8654482ee2.Models;
using sv_89570eeee9ef42baa859fc8654482ee2.Services;

namespace sv_89570eeee9ef42baa859fc8654482ee2.Components.Pages.Apply;

/// <summary>
/// Base class for wizard pages. Handles session key bridging from
/// SSR prerender (where HttpContext is available) to interactive mode
/// (where it is not) via PersistentComponentState.
/// </summary>
public abstract class WizardPageBase : ComponentBase, IDisposable
{
    [Inject] protected WizardStateService WizardService { get; set; } = default!;
    [Inject] protected IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected NavigationManager Navigation { get; set; } = default!;

    protected string SessionKey { get; private set; } = "";
    protected WizardData WizardData { get; private set; } = new();
    protected bool IsLoaded { get; private set; }

    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(PersistSessionKey);

        // Try to retrieve the key persisted from prerender.
        // If not found, we're in the prerender pass — read from HttpContext.Items
        // (set by the cookie middleware to handle even the very first request).
        if (!PersistentState.TryTakeFromJson<string>("WizardSessionKey", out var key))
        {
            key = HttpContextAccessor.HttpContext?.Items["WizardSessionId"] as string;
        }

        SessionKey = key ?? "";

        if (!string.IsNullOrEmpty(SessionKey))
        {
            WizardData = WizardService.GetOrCreate(SessionKey);
            WizardData.LastAccessed = DateTime.UtcNow;
            IsLoaded = true;
        }
    }

    private Task PersistSessionKey()
    {
        PersistentState.PersistAsJson("WizardSessionKey", SessionKey);
        return Task.CompletedTask;
    }

    protected void NavigateToStep(string path)
    {
        Navigation.NavigateTo(path);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

