using sv_89570eeee9ef42baa859fc8654482ee2.Components;
using sv_89570eeee9ef42baa859fc8654482ee2.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddHttpContextAccessor();
builder.Services.AddSingleton<WizardStateService>();
builder.Services.AddHostedService<WizardCleanupService>();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);

// Assign a session cookie for wizard state isolation.
// Stores the key in HttpContext.Items so it's available on the very first request
// (before the browser sends the cookie back).
app.Use(async (context, next) =>
{
    if (!context.Request.Cookies.TryGetValue("WizardSessionId", out var sessionId))
    {
        sessionId = Guid.NewGuid().ToString();
        context.Response.Cookies.Append("WizardSessionId", sessionId, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(24)
        });
    }
    context.Items["WizardSessionId"] = sessionId;
    await next();
});

app.UseAntiforgery();

