@code {
    private const int TotalSteps = 4;
    private WizardData? _wizardData;

    // The layout is static SSR — it re-renders on every navigation.
    // HttpContext is always available here, so we can read the session cookie
    // and look up wizard state directly from the singleton service.
    private bool IsApplyPage =>
        HttpContextAccessor.HttpContext?.Request.Path.StartsWithSegments("/apply") == true;

    private int CurrentStep => _wizardData?.CurrentStep ?? 1;

    protected override void OnInitialized()
    {
        var sessionId = HttpContextAccessor.HttpContext?.Items["WizardSessionId"] as string;
        if (!string.IsNullOrEmpty(sessionId) && IsApplyPage)
        {
            _wizardData = WizardService.GetOrCreate(sessionId);
        }
    }

    private static string StepUrl(int step) => step switch
    {
        1 => "/apply/personal-info",
        2 => "/apply/experience",
        3 => "/apply/references",
        4 => "/apply/review",
        _ => "/apply/personal-info"
    };

    private static string StepLabel(int step) => step switch
    {
        1 => "Personal",
        2 => "Experience",
        3 => "References",
        4 => "Review",
        _ => ""
    };
